// frontend/src/pages/Cultura.js

const Cultura = ({ sitios }) => { // <--- Asegúrate de que diga { sitios }
  return (
    <div className="cultura-container">
      <h1>Sitios Culturales de La Paz</h1>
      <div className="grid">
        {sitios && sitios.map((sitio) => (
          <div key={sitio.id_sitio} className="card"> 
            <h3>{sitio.nombre}</h3>
            <p>{sitio.descripcion}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Cultura;
